// Simulated polysemy resolution via tree routing
const verbs = [
  { verb: 'shot', args: 'the target', path: ['ROOT','CAUSE','PROPEL','SHOOT'], weights: [1,.9,.85,.95] },
  { verb: 'shot', args: 'him a glance', path: ['ROOT','TRANSFER','MTRANS','COMMUNICATE'], weights: [1,.8,.9,.88] },
  { verb: 'shot', args: 'the scene', path: ['ROOT','CAUSE','CREATE','RECORD'], weights: [1,.75,.82,.91] },
  { verb: 'cut', args: 'the rope', path: ['ROOT','CAUSE','PROPEL','SEPARATE'], weights: [1,.88,.79,.93] },
  { verb: 'cut', args: 'the budget', path: ['ROOT','CAUSE','DECREASE','REDUCE'], weights: [1,.72,.84,.87] },
  { verb: 'cut', args: 'class today', path: ['ROOT','MOVE','AVOID','SKIP'], weights: [1,.65,.78,.90] },
  { verb: 'run', args: 'a marathon', path: ['ROOT','MOVE','PTRANS','LOCOMOTE'], weights: [1,.92,.88,.96] },
  { verb: 'run', args: 'a company', path: ['ROOT','CAUSE','CONTROL','MANAGE'], weights: [1,.7,.81,.89] },
  { verb: 'run', args: 'a program', path: ['ROOT','CAUSE','ACTIVATE','EXECUTE'], weights: [1,.68,.76,.92] }
];
const idx = Math.floor(Date.now() / 3000) % verbs.length;
const v = verbs[idx];
const pathStr = v.path.map((p,i) => {
  const bar = '█'.repeat(Math.round(v.weights[i]*10));
  return `${'  '.repeat(i)}${p} ${bar} ${(v.weights[i]*100).toFixed(0)}%`;
}).join('\n');
return `Verb: "${v.verb}" + "${v.args}"\n\nTree Routing (confidence):\n${pathStr}\n\n→ Final operator: ${v.path[v.path.length-1]}\n\n(changes every 3 seconds — watch polysemy resolve!)`;

// Comparing tree embedding in Euclidean vs Hyperbolic space
const levels = [
  { name: 'ROOT', euc_r: 0.5, hyp_r: 0.1, children: 5 },
  { name: 'CAUSE', euc_r: 0.25, hyp_r: 0.3, children: 4 },
  { name: 'PROPEL', euc_r: 0.12, hyp_r: 0.6, children: 6 },
  { name: 'KICK', euc_r: 0.06, hyp_r: 0.85, children: 0 }
];
const eucVol = (r) => (4/3 * Math.PI * r**3).toFixed(3);
const hypVol = (r) => (Math.PI * (Math.cosh(2*r*3) - 1)).toFixed(1);
let out = 'Level        Euclidean Vol   Hyperbolic Vol   Children Fit?\n';
out += '─'.repeat(65) + '\n';
for (const l of levels) {
  const ev = eucVol(l.euc_r);
  const hv = hypVol(l.hyp_r);
  const fit = l.children === 0 ? 'leaf' : (parseFloat(hv) > l.children ? '✅ plenty' : '❌ cramped');
  out += `${l.name.padEnd(12)} ${ev.padStart(10)}       ${hv.padStart(10)}        ${fit}\n`;
}
out += '\n💡 Hyperbolic volume grows EXPONENTIALLY with radius —';
out += '\n   trees embed naturally without crowding leaves!';
return out;

// Visualize how complex verbs decompose into operator tree paths
const decompositions = {
  'teach': {
    primary: ['CAUSE', 'MTRANS'],
    secondary: ['MBUILD'],
    formula: 'CAUSE(agent, MTRANS(info, src→dst)) ∘ MBUILD(patient, info)',
    example: 'John taught Mary calculus'
  },
  'steal': {
    primary: ['CAUSE', 'ATRANS'],
    secondary: ['MOVE'],
    formula: 'CAUSE(agent, ATRANS(obj, victim→agent)) ∘ MOVE(agent, loc)',
    example: 'The thief stole the painting'
  },
  'assassinate': {
    primary: ['CAUSE', 'PROPEL'],
    secondary: ['HARM', 'TERMINATE'],
    formula: 'CAUSE(agent, PROPEL(weapon)) → HARM(patient) → TERMINATE(patient.alive)',
    example: 'The spy assassinated the general'
  },
  'bribe': {
    primary: ['ATRANS', 'CAUSE'],
    secondary: ['MBUILD'],
    formula: 'ATRANS(money, agent→target) → CAUSE(target, MBUILD(target, obligation))',
    example: 'The lobbyist bribed the senator'
  }
};
const keys = Object.keys(decompositions);
const idx = Math.floor(Date.now() / 4000) % keys.length;
const verb = keys[idx];
const d = decompositions[verb];
let out = `Verb: "${verb}"\nExample: ${d.example}\n\n`;
out += `Decomposition:\n  ${d.formula}\n\n`;
out += `Primary tree paths: ${d.primary.join(' + ')}\n`;
out += `Secondary paths:    ${d.secondary.join(' + ')}\n\n`;
out += `Tree visualization:\n`;
out += `  ROOT\n`;
for (const p of d.primary) {
  out += `  ├── ${p} ◀━━ primary\n`;
}
for (const s of d.secondary) {
  out += `  └── ${s} ◁── secondary\n`;
}
out += `\n(cycles every 4s — watch different verbs decompose!)`;
return out;

// Demonstrate the containment loss function
function containmentLoss(parent_center, parent_radius, child_center, child_radius) {
  const dist = Math.sqrt(parent_center.reduce((s, v, i) => s + (v - child_center[i])**2, 0));
  const violation = Math.max(0, (dist + child_radius) - parent_radius);
  return violation;
}

const examples = [
  { parent: 'CAUSE', child: 'PROPEL', pc: [0,0], pr: 3.0, cc: [0.5, 0.3], cr: 1.0 },
  { parent: 'CAUSE', child: 'LET', pc: [0,0], pr: 3.0, cc: [1.8, 1.2], cr: 0.8 },
  { parent: 'PROPEL', child: 'KICK', pc: [0.5,0.3], pr: 1.0, cc: [0.7, 0.5], cr: 0.3 },
  { parent: 'TRANSFER', child: 'KICK', pc: [-2,0], pr: 2.5, cc: [0.7, 0.5], cr: 0.3 }
];

let out = 'Parent       Child     Dist   Violation   Status\n';
out += '─'.repeat(55) + '\n';
for (const e of examples) {
  const loss = containmentLoss(e.pc, e.pr, e.cc, e.cr);
  const dist = Math.sqrt(e.pc.reduce((s, v, i) => s + (v - e.cc[i])**2, 0)).toFixed(2);
  const status = loss === 0 ? '✅ nested' : '❌ violation';
  out += `${e.parent.padEnd(12)} ${e.child.padEnd(9)} ${dist.padStart(5)}   ${loss.toFixed(2).padStart(8)}     ${status}\n`;
}
out += '\nLoss = max(0, dist(parent, child) + child_radius - parent_radius)';
out += '\nZero loss = child ball fully inside parent ball';
return out;
